                <div class="col-lg-10">
                    <div class="destination-details-content">
                        <h2>Agra</h2>
                        <ul class="destination-info">
                            <li>
                                <div class="content">
                                    <span>Capital -</span> New Delhi
                                </div>
                            </li>
                            <li>
                                <div class="content">
